using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Models;

namespace VetClinic.Services;

public class PatientService(ApplicationDbContext db)
{
    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        var query = db.Owners.Include(o => o.Pets).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            search = search.ToLower();
            query = query.Where(o => o.FirstName.ToLower().Contains(search)
                                  || o.LastName.ToLower().Contains(search)
                                  || o.Pets.Any(p => p.Name.ToLower().Contains(search)));
        }
        return await query.OrderBy(o => o.LastName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id) =>
        await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);

    public async Task SaveOwnerAsync(Owner owner)
    {
        if (owner.Id == 0) db.Owners.Add(owner);
        else db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    public async Task<Pet?> GetPetAsync(int id) =>
        await db.Pets.Include(p => p.Owner)
                     .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
                     .FirstOrDefaultAsync(p => p.Id == id);

    public async Task<List<Pet>> GetPetsAsync(string? search = null)
    {
        var query = db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            search = search.ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(search)
                                  || p.Owner.LastName.ToLower().Contains(search));
        }
        return await query.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task SavePetAsync(Pet pet)
    {
        if (pet.Id == 0) db.Pets.Add(pet);
        else db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task AddTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Add(note);
        await db.SaveChangesAsync();
    }

    public async Task<TreatmentNote?> GetTreatmentNoteAsync(int id) =>
        await db.TreatmentNotes.FindAsync(id);

    public async Task UpdateTreatmentNoteAsync(TreatmentNote note)
    {
        db.TreatmentNotes.Update(note);
        await db.SaveChangesAsync();
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Models;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetAppointmentsForDateRangeAsync(DateTime start, DateTime end)
    {
        return await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= start && a.StartTime < end && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id) =>
        await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).FirstOrDefaultAsync(a => a.Id == id);

    public async Task<bool> IsSlotAvailableAsync(DateTime start, DateTime end, int? excludeId = null)
    {
        var query = db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => a.StartTime < end && a.EndTime > start);

        if (excludeId.HasValue)
            query = query.Where(a => a.Id != excludeId.Value);

        return !await query.AnyAsync();
    }

    public async Task<List<(DateTime Start, DateTime End)>> GetAvailableSlotsAsync(DateOnly date)
    {
        var dayStart = date.ToDateTime(new TimeOnly(8, 0));
        var dayEnd = date.ToDateTime(new TimeOnly(18, 0));

        var booked = await db.Appointments
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .Select(a => new { a.StartTime, a.EndTime })
            .ToListAsync();

        var slots = new List<(DateTime, DateTime)>();
        var current = dayStart;

        foreach (var appt in booked)
        {
            if (current < appt.StartTime)
                slots.Add((current, appt.StartTime));
            if (appt.EndTime > current)
                current = appt.EndTime;
        }

        if (current < dayEnd)
            slots.Add((current, dayEnd));

        return slots;
    }

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        if (appointment.Id == 0) db.Appointments.Add(appointment);
        else db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? status = null)
    {
        var query = db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (status.HasValue)
            query = query.Where(i => i.Status == status.Value);

        return await query.OrderByDescending(i => i.DateIssued).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id) =>
        await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0) db.Invoices.Add(invoice);
        else db.Invoices.Update(invoice);
        await db.SaveChangesAsync();
    }

    public async Task AddInvoiceItemAsync(InvoiceItem item)
    {
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveInvoiceItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item != null)
        {
            db.InvoiceItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    public async Task ProcessPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);

        var invoice = await db.Invoices.Include(i => i.Items).Include(i => i.Payments).FirstAsync(i => i.Id == payment.InvoiceId);
        var totalPaid = invoice.Payments.Where(p => !p.IsRefund).Sum(p => p.Amount)
                      - invoice.Payments.Where(p => p.IsRefund).Sum(p => p.Amount)
                      + (payment.IsRefund ? -payment.Amount : payment.Amount);

        if (totalPaid >= invoice.Items.Sum(i => i.Amount * i.Quantity))
            invoice.Status = InvoiceStatus.Paid;

        await db.SaveChangesAsync();
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
    {
        var query = db.Payments.Include(p => p.Invoice).ThenInclude(i => i.Pet).AsQueryable();
        if (invoiceId.HasValue)
            query = query.Where(p => p.InvoiceId == invoiceId.Value);
        return await query.OrderByDescending(p => p.Date).ToListAsync();
    }
}

