@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Nav

<PageTitle>Patients</PageTitle>

<h3>Patient Records</h3>

<div class="row mb-3">
    <div class="col-md-6">
        <input class="form-control" placeholder="Search by pet or owner name..." @bind="searchTerm" @bind:event="oninput" @onkeyup="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-success" @onclick="ShowNewOwnerForm">+ New Owner</button>
        <button class="btn btn-primary ms-2" @onclick="ShowNewPetForm">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="First Name" @bind="editingOwner.FirstName" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Last Name" @bind="editingOwner.LastName" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Phone" @bind="editingOwner.Phone" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Email" @bind="editingOwner.Email" />
                </div>
            </div>
            <div class="mt-2">
                <button class="btn btn-primary" @onclick="SaveOwner">Save</button>
                <button class="btn btn-secondary ms-2" @onclick="() => showOwnerForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</h5>
            <div class="row g-2">
                <div class="col-md-2">
                    <input class="form-control" placeholder="Name" @bind="editingPet.Name" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Species" @bind="editingPet.Species" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Breed" @bind="editingPet.Breed" />
                </div>
                <div class="col-md-2">
                    <label class="form-label small">Date of Birth</label>
                    <input type="date" class="form-control" @bind="petDob" />
                </div>
                <div class="col-md-2">
                    <input type="number" step="0.1" class="form-control" placeholder="Weight (kg)" @bind="editingPet.WeightKg" />
                </div>
                <div class="col-md-2">
                    <select class="form-select" @bind="editingPet.OwnerId">
                        <option value="0">Select Owner</option>
                        @foreach (var owner in owners)
                        {
                            <option value="@owner.Id">@owner.FullName</option>
                        }
                    </select>
                </div>
            </div>
            <div class="mt-2">
                <button class="btn btn-primary" @onclick="SavePet">Save</button>
                <button class="btn btn-secondary ms-2" @onclick="() => showPetForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>Pet Name</th>
            <th>Species</th>
            <th>Breed</th>
            <th>Owner</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var pet in pets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => ViewPet(pet.Id)">View</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditPet(pet)">Edit</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<VetClinic.Models.Pet> pets = [];
    private List<VetClinic.Models.Owner> owners = [];
    private string searchTerm = "";
    private bool showOwnerForm, showPetForm;
    private VetClinic.Models.Owner editingOwner = new();
    private VetClinic.Models.Pet editingPet = new();
    private DateTime petDob = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await PatientService.GetPetsAsync(searchTerm);
        owners = await PatientService.GetOwnersAsync();
    }

    private async Task Search() => await LoadData();

    private void ShowNewOwnerForm()
    {
        editingOwner = new();
        showOwnerForm = true;
    }

    private void ShowNewPetForm()
    {
        editingPet = new();
        petDob = DateTime.Today;
        showPetForm = true;
    }

    private async Task SaveOwner()
    {
        await PatientService.SaveOwnerAsync(editingOwner);
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        editingPet.DateOfBirth = DateOnly.FromDateTime(petDob);
        await PatientService.SavePetAsync(editingPet);
        showPetForm = false;
        await LoadData();
    }

    private void EditPet(VetClinic.Models.Pet pet)
    {
        editingPet = pet;
        petDob = pet.DateOfBirth.ToDateTime(TimeOnly.MinValue);
        showPetForm = true;
    }

    private void ViewPet(int id) => Nav.NavigateTo($"/patients/{id}");
}

@page "/patients/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Nav

<PageTitle>Patient Details</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <h3>@pet.Name <small class="text-muted">(@pet.Species - @pet.Breed)</small></h3>
    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-body">
                    <p><strong>Owner:</strong> @pet.Owner.FullName</p>
                    <p><strong>Date of Birth:</strong> @pet.DateOfBirth.ToString("yyyy-MM-dd")</p>
                    <p><strong>Weight:</strong> @pet.WeightKg kg</p>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="EditPatient">Edit Details</button>
                </div>
            </div>
        </div>
    </div>

    @if (showEditForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5>Edit Patient</h5>
                <div class="row g-2">
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Name" @bind="pet.Name" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Species" @bind="pet.Species" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Breed" @bind="pet.Breed" />
                    </div>
                    <div class="col-md-3">
                        <input type="number" step="0.1" class="form-control" placeholder="Weight (kg)" @bind="pet.WeightKg" />
                    </div>
                </div>
                <div class="mt-2">
                    <button class="btn btn-primary" @onclick="SavePatient">Save</button>
                    <button class="btn btn-secondary ms-2" @onclick="() => showEditForm = false">Cancel</button>
                </div>
            </div>
        </div>
    }

    <h4 class="mt-4">Medical History</h4>
    <button class="btn btn-success mb-3" @onclick="ShowAddNote">+ Add Treatment Note</button>

    @if (showNoteForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5>@(editingNote.Id == 0 ? "New Treatment Note" : "Edit Treatment Note")</h5>
                <div class="row g-2">
                    <div class="col-md-6">
                        <label class="form-label">Diagnosis</label>
                        <input class="form-control" @bind="editingNote.Diagnosis" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Veterinarian</label>
                        <input class="form-control" @bind="editingNote.VeterinarianName" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Treatment</label>
                        <textarea class="form-control" rows="2" @bind="editingNote.Treatment"></textarea>
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Medications</label>
                        <textarea class="form-control" rows="2" @bind="editingNote.Medications"></textarea>
                    </div>
                    <div class="col-12">
                        <label class="form-label">Notes</label>
                        <textarea class="form-control" rows="2" @bind="editingNote.Notes"></textarea>
                    </div>
                </div>
                <div class="mt-2">
                    <button class="btn btn-primary" @onclick="SaveNote">Save</button>
                    <button class="btn btn-secondary ms-2" @onclick="() => showNoteForm = false">Cancel</button>
                </div>
            </div>
        </div>
    }

    @if (pet.TreatmentNotes.Count == 0)
    {
        <p class="text-muted">No treatment notes recorded.</p>
    }
    else
    {
        @foreach (var note in pet.TreatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <strong>@note.Date.ToString("yyyy-MM-dd HH:mm")</strong>
                        <span class="text-muted">Dr. @note.VeterinarianName</span>
                    </div>
                    <p class="mb-1"><strong>Diagnosis:</strong> @note.Diagnosis</p>
                    <p class="mb-1"><strong>Treatment:</strong> @note.Treatment</p>
                    @if (!string.IsNullOrEmpty(note.Medications))
                    {
                        <p class="mb-1"><strong>Medications:</strong> @note.Medications</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Notes))
                    {
                        <p class="mb-0"><strong>Notes:</strong> @note.Notes</p>
                    }
                    <button class="btn btn-sm btn-outline-secondary mt-1" @onclick="() => EditNote(note)">Edit</button>
                </div>
            </div>
        }
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private VetClinic.Models.Pet? pet;
    private bool showEditForm, showNoteForm;
    private VetClinic.Models.TreatmentNote editingNote = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadPet();
    }

    private async Task LoadPet()
    {
        pet = await PatientService.GetPetAsync(Id);
    }

    private void EditPatient() => showEditForm = true;

    private async Task SavePatient()
    {
        if (pet != null)
        {
            await PatientService.SavePetAsync(pet);
            showEditForm = false;
        }
    }

    private void ShowAddNote()
    {
        editingNote = new() { PetId = Id };
        showNoteForm = true;
    }

    private void EditNote(VetClinic.Models.TreatmentNote note)
    {
        editingNote = note;
        showNoteForm = true;
    }

    private async Task SaveNote()
    {
        if (editingNote.Id == 0)
        {
            editingNote.Date = DateTime.Now;
            await PatientService.AddTreatmentNoteAsync(editingNote);
        }
        else
        {
            await PatientService.UpdateTreatmentNoteAsync(editingNote);
        }
        showNoteForm = false;
        await LoadPet();
    }
}

@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer
@inject VetClinic.Services.AppointmentService AppointmentService
@inject VetClinic.Services.PatientService PatientService

<PageTitle>Appointments</PageTitle>

<h3>Appointment Calendar</h3>

<div class="row mb-3">
    <div class="col-md-4">
        <div class="input-group">
            <button class="btn btn-outline-secondary" @onclick="PrevDay">&lt;</button>
            <input type="date" class="form-control" @bind="selectedDate" @bind:event="onchange" @bind:after="LoadAppointments" />
            <button class="btn btn-outline-secondary" @onclick="NextDay">&gt;</button>
        </div>
    </div>
    <div class="col-md-4">
        <button class="btn btn-outline-primary" @onclick="GoToToday">Today</button>
    </div>
    <div class="col-md-4 text-end">
        <button class="btn btn-success" @onclick="ShowNewForm">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingAppointment.Id == 0 ? "New Appointment" : "Reschedule Appointment")</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="editingAppointment.PetId">
                        <option value="0">Select Pet</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-2">
                    <label class="form-label">Date</label>
                    <input type="date" class="form-control" @bind="apptDate" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Start Time</label>
                    <input type="time" class="form-control" @bind="apptStartTime" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">End Time</label>
                    <input type="time" class="form-control" @bind="apptEndTime" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Veterinarian</label>
                    <input class="form-control" @bind="editingAppointment.VeterinarianName" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Reason</label>
                    <input class="form-control" @bind="editingAppointment.Reason" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Notes</label>
                    <input class="form-control" @bind="editingAppointment.Notes" />
                </div>
            </div>
            @if (!string.IsNullOrEmpty(formError))
            {
                <div class="alert alert-danger mt-2">@formError</div>
            }
            <div class="mt-2">
                <button class="btn btn-primary" @onclick="SaveAppointment">Save</button>
                <button class="btn btn-secondary ms-2" @onclick="() => showForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

<h5>Available Slots</h5>
<div class="mb-3">
    @if (availableSlots.Count == 0)
    {
        <span class="text-muted">No available slots for this day.</span>
    }
    else
    {
        @foreach (var slot in availableSlots)
        {
            <span class="badge bg-success me-1">@slot.Start.ToString("HH:mm") - @slot.End.ToString("HH:mm")</span>
        }
    }
</div>

<h5>Scheduled Appointments</h5>
<table class="table table-striped">
    <thead>
        <tr>
            <th>Time</th>
            <th>Pet</th>
            <th>Owner</th>
            <th>Reason</th>
            <th>Vet</th>
            <th>Status</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var appt in appointments)
        {
            <tr>
                <td>@appt.StartTime.ToString("HH:mm") - @appt.EndTime.ToString("HH:mm")</td>
                <td>@appt.Pet.Name</td>
                <td>@appt.Pet.Owner.FullName</td>
                <td>@appt.Reason</td>
                <td>@appt.VeterinarianName</td>
                <td><span class="badge @GetStatusBadge(appt.Status)">@appt.Status</span></td>
                <td>
                    @if (appt.Status == VetClinic.Models.AppointmentStatus.Scheduled)
                    {
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(appt)">Reschedule</button>
                        <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => Cancel(appt.Id)">Cancel</button>
                    }
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<VetClinic.Models.Appointment> appointments = [];
    private List<(DateTime Start, DateTime End)> availableSlots = [];
    private List<VetClinic.Models.Pet> pets = [];
    private bool showForm;
    private VetClinic.Models.Appointment editingAppointment = new();
    private DateTime apptDate = DateTime.Today;
    private TimeSpan apptStartTime = new(9, 0, 0);
    private TimeSpan apptEndTime = new(9, 30, 0);
    private string formError = "";

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetPetsAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var dayStart = selectedDate.Date;
        var dayEnd = dayStart.AddDays(1);
        appointments = await AppointmentService.GetAppointmentsForDateRangeAsync(dayStart, dayEnd);
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(DateOnly.FromDateTime(selectedDate));
    }

    private async Task PrevDay() { selectedDate = selectedDate.AddDays(-1); await LoadAppointments(); }
    private async Task NextDay() { selectedDate = selectedDate.AddDays(1); await LoadAppointments(); }
    private async Task GoToToday() { selectedDate = DateTime.Today; await LoadAppointments(); }

    private void ShowNewForm()
    {
        editingAppointment = new();
        apptDate = selectedDate;
        apptStartTime = new(9, 0, 0);
        apptEndTime = new(9, 30, 0);
        formError = "";
        showForm = true;
    }

    private void Reschedule(VetClinic.Models.Appointment appt)
    {
        editingAppointment = appt;
        apptDate = appt.StartTime.Date;
        apptStartTime = appt.StartTime.TimeOfDay;
        apptEndTime = appt.EndTime.TimeOfDay;
        formError = "";
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        editingAppointment.StartTime = apptDate.Date + apptStartTime;
        editingAppointment.EndTime = apptDate.Date + apptEndTime;

        var available = await AppointmentService.IsSlotAvailableAsync(
            editingAppointment.StartTime, editingAppointment.EndTime,
            editingAppointment.Id == 0 ? null : editingAppointment.Id);

        if (!available)
        {
            formError = "This time slot conflicts with an existing appointment.";
            return;
        }

        editingAppointment.Status = VetClinic.Models.AppointmentStatus.Scheduled;
        await AppointmentService.SaveAppointmentAsync(editingAppointment);
        showForm = false;
        formError = "";
        await LoadAppointments();
    }

    private async Task Cancel(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadAppointments();
    }

    private string GetStatusBadge(VetClinic.Models.AppointmentStatus status) => status switch
    {
        VetClinic.Models.AppointmentStatus.Scheduled => "bg-primary",
        VetClinic.Models.AppointmentStatus.Completed => "bg-success",
        VetClinic.Models.AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

@page "/billing"
@attribute [Authorize]
@rendermode InteractiveServer
@inject VetClinic.Services.BillingService BillingService
@inject VetClinic.Services.PatientService PatientService
@inject NavigationManager Nav

<PageTitle>Billing</PageTitle>

<h3>Billing</h3>

<div class="row mb-3">
    <div class="col-md-4">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadInvoices">
            <option value="">All Invoices</option>
            <option value="Pending">Pending</option>
            <option value="Paid">Paid</option>
            <option value="Overdue">Overdue</option>
        </select>
    </div>
    <div class="col-md-4">
        <button class="btn btn-outline-info" @onclick="ShowPaymentHistory">Payment History</button>
    </div>
    <div class="col-md-4 text-end">
        <button class="btn btn-success" @onclick="ShowNewInvoice">+ New Invoice</button>
    </div>
</div>

@if (showNewInvoiceForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>New Invoice</h5>
            <div class="row g-2">
                <div class="col-md-4">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="newInvoice.PetId">
                        <option value="0">Select Pet</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-4">
                    <label class="form-label">Due Date</label>
                    <input type="date" class="form-control" @bind="invoiceDueDate" />
                </div>
            </div>
            <div class="mt-2">
                <button class="btn btn-primary" @onclick="CreateInvoice">Create</button>
                <button class="btn btn-secondary ms-2" @onclick="() => showNewInvoiceForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (showHistory)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Payment History</h5>
            <button class="btn btn-sm btn-outline-secondary mb-2" @onclick="() => showHistory = false">Close</button>
            <table class="table table-sm">
                <thead>
                    <tr><th>Date</th><th>Invoice #</th><th>Pet</th><th>Amount</th><th>Method</th><th>Type</th></tr>
                </thead>
                <tbody>
                    @foreach (var p in paymentHistory)
                    {
                        <tr>
                            <td>@p.Date.ToString("yyyy-MM-dd")</td>
                            <td>#@p.InvoiceId</td>
                            <td>@p.Invoice.Pet.Name</td>
                            <td>@p.Amount.ToString("C")</td>
                            <td>@p.Method</td>
                            <td>@(p.IsRefund ? "Refund" : "Payment")</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>#</th>
            <th>Date</th>
            <th>Pet</th>
            <th>Owner</th>
            <th>Total</th>
            <th>Paid</th>
            <th>Balance</th>
            <th>Status</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            <tr>
                <td>@inv.Id</td>
                <td>@inv.DateIssued.ToString("yyyy-MM-dd")</td>
                <td>@inv.Pet.Name</td>
                <td>@inv.Pet.Owner.FullName</td>
                <td>@inv.Total.ToString("C")</td>
