    private List<VetClinic.Models.Appointment> appointments = [];
    private List<(DateTime Start, DateTime End)> availableSlots = [];
    private List<VetClinic.Models.Pet> pets = [];
    private bool showForm;
    private VetClinic.Models.Appointment editingAppointment = new();
    private DateTime apptDate = DateTime.Today;
    private TimeSpan apptStartTime = new(9, 0, 0);
    private TimeSpan apptEndTime = new(9, 30, 0);
    private string formError = "";

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetPetsAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var dayStart = selectedDate.Date;
        var dayEnd = dayStart.AddDays(1);
        appointments = await AppointmentService.GetAppointmentsForDateRangeAsync(dayStart, dayEnd);
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(DateOnly.FromDateTime(selectedDate));
    }

    private async Task PrevDay() { selectedDate = selectedDate.AddDays(-1); await LoadAppointments(); }
    private async Task NextDay() { selectedDate = selectedDate.AddDays(1); await LoadAppointments(); }
    private async Task GoToToday() { selectedDate = DateTime.Today; await LoadAppointments(); }

    private void ShowNewForm()
    {
        editingAppointment = new();
        apptDate = selectedDate;
        apptStartTime = new(9, 0, 0);
        apptEndTime = new(9, 30, 0);
        formError = "";
        showForm = true;
    }

    private void Reschedule(VetClinic.Models.Appointment appt)
    {
        editingAppointment = appt;
        apptDate = appt.StartTime.Date;
        apptStartTime = appt.StartTime.TimeOfDay;
        apptEndTime = appt.EndTime.TimeOfDay;
        formError = "";
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        editingAppointment.StartTime = apptDate.Date + apptStartTime;
        editingAppointment.EndTime = apptDate.Date + apptEndTime;

        var available = await AppointmentService.IsSlotAvailableAsync(
            editingAppointment.StartTime, editingAppointment.EndTime,
            editingAppointment.Id == 0 ? null : editingAppointment.Id);

        if (!available)
        {
            formError = "This time slot conflicts with an existing appointment.";
            return;
        }

        editingAppointment.Status = VetClinic.Models.AppointmentStatus.Scheduled;
        await AppointmentService.SaveAppointmentAsync(editingAppointment);
        showForm = false;
        formError = "";
        await LoadAppointments();
    }

    private async Task Cancel(int id)
    {
        await AppointmentService.CancelAppointmentAsync(id);
        await LoadAppointments();
    }

    private string GetStatusBadge(VetClinic.Models.AppointmentStatus status) => status switch
    {
        VetClinic.Models.AppointmentStatus.Scheduled => "bg-primary",
        VetClinic.Models.AppointmentStatus.Completed => "bg-success",
        VetClinic.Models.AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

