<div class="row mb-3">
    <div class="col-md-4">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadInvoices">
            <option value="">All Invoices</option>
            <option value="Pending">Pending</option>
            <option value="Paid">Paid</option>
            <option value="Overdue">Overdue</option>
        </select>
    </div>
    <div class="col-md-4">
        <button class="btn btn-outline-info" @onclick="ShowPaymentHistory">Payment History</button>
    </div>
    <div class="col-md-4 text-end">
        <button class="btn btn-success" @onclick="ShowNewInvoice">+ New Invoice</button>
    </div>
</div>

@if (showNewInvoiceForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>New Invoice</h5>
            <div class="row g-2">
                <div class="col-md-4">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="newInvoice.PetId">
                        <option value="0">Select Pet</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-4">
                    <label class="form-label">Due Date</label>
                    <input type="date" class="form-control" @bind="invoiceDueDate" />
                </div>
            </div>
            <div class="mt-2">
                <button class="btn btn-primary" @onclick="CreateInvoice">Create</button>
                <button class="btn btn-secondary ms-2" @onclick="() => showNewInvoiceForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (showHistory)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Payment History</h5>
            <button class="btn btn-sm btn-outline-secondary mb-2" @onclick="() => showHistory = false">Close</button>
            <table class="table table-sm">
                <thead>
                    <tr><th>Date</th><th>Invoice #</th><th>Pet</th><th>Amount</th><th>Method</th><th>Type</th></tr>
                </thead>
                <tbody>
                    @foreach (var p in paymentHistory)
                    {
                        <tr>
                            <td>@p.Date.ToString("yyyy-MM-dd")</td>
                            <td>#@p.InvoiceId</td>
                            <td>@p.Invoice.Pet.Name</td>
                            <td>@p.Amount.ToString("C")</td>
                            <td>@p.Method</td>
                            <td>@(p.IsRefund ? "Refund" : "Payment")</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>#</th>
            <th>Date</th>
            <th>Pet</th>
            <th>Owner</th>
            <th>Total</th>
            <th>Paid</th>
            <th>Balance</th>
            <th>Status</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            <tr>
                <td>@inv.Id</td>
                <td>@inv.DateIssued.ToString("yyyy-MM-dd")</td>
                <td>@inv.Pet.Name</td>
                <td>@inv.Pet.Owner.FullName</td>
                <td>@inv.Total.ToString("C")</td>
                <td>@inv.AmountPaid.ToString("C")</td>
                <td>@inv.Balance.ToString("C")</td>
                <td><span class="badge @GetStatusBadge(inv.Status)">@inv.Status</span></td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => ViewInvoice(inv.Id)">Details</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<VetClinic.Models.Invoice> invoices = [];
    private List<VetClinic.Models.Pet> pets = [];
    private List<VetClinic.Models.Payment> paymentHistory = [];
    private string statusFilter = "";
    private bool showNewInvoiceForm, showHistory;
    private VetClinic.Models.Invoice newInvoice = new();
    private DateTime invoiceDueDate = DateTime.Today.AddDays(30);

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetPetsAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        VetClinic.Models.InvoiceStatus? status = statusFilter switch
        {
            "Pending" => VetClinic.Models.InvoiceStatus.Pending,
            "Paid" => VetClinic.Models.InvoiceStatus.Paid,
            "Overdue" => VetClinic.Models.InvoiceStatus.Overdue,
            _ => null
        };
        invoices = await BillingService.GetInvoicesAsync(status);
    }

    private void ShowNewInvoice()
    {
        newInvoice = new();
        invoiceDueDate = DateTime.Today.AddDays(30);
        showNewInvoiceForm = true;
    }

    private async Task CreateInvoice()
    {
        newInvoice.DateIssued = DateTime.Now;
        newInvoice.DateDue = invoiceDueDate;
        await BillingService.SaveInvoiceAsync(newInvoice);
        showNewInvoiceForm = false;
        await LoadInvoices();
    }

    private async Task ShowPaymentHistory()
    {
        paymentHistory = await BillingService.GetPaymentHistoryAsync();
        showHistory = true;
    }

    private void ViewInvoice(int id) => Nav.NavigateTo($"/billing/{id}");

    private string GetStatusBadge(VetClinic.Models.InvoiceStatus status) => status switch
    {
        VetClinic.Models.InvoiceStatus.Pending => "bg-warning text-dark",
        VetClinic.Models.InvoiceStatus.Paid => "bg-success",
        VetClinic.Models.InvoiceStatus.Overdue => "bg-danger",
        VetClinic.Models.InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

@page "/billing/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer
@inject VetClinic.Services.BillingService BillingService

<PageTitle>Invoice Details</PageTitle>

@if (invoice == null)
{
    <p>Loading...</p>
}
else
{
    <h3>Invoice #@invoice.Id</h3>
    <div class="row mb-3">
        <div class="col-md-6">
            <p><strong>Pet:</strong> @invoice.Pet.Name</p>
            <p><strong>Owner:</strong> @invoice.Pet.Owner.FullName</p>
            <p><strong>Issued:</strong> @invoice.DateIssued.ToString("yyyy-MM-dd")</p>
            <p><strong>Due:</strong> @invoice.DateDue?.ToString("yyyy-MM-dd")</p>
            <p><strong>Status:</strong> <span class="badge @GetStatusBadge(invoice.Status)">@invoice.Status</span></p>
        </div>
        <div class="col-md-6 text-end">
            <h4>Total: @invoice.Total.ToString("C")</h4>
            <h5 class="text-success">Paid: @invoice.AmountPaid.ToString("C")</h5>
            <h5 class="text-danger">Balance: @invoice.Balance.ToString("C")</h5>
        </div>
    </div>

    <h5>Line Items</h5>
    <table class="table table-sm">
        <thead>
            <tr><th>Description</th><th>Qty</th><th>Amount</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var item in invoice.Items)
            {
                <tr>
                    <td>@item.Description</td>
                    <td>@item.Quantity</td>
                    <td>@item.Amount.ToString("C")</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveItem(item.Id)">Remove</button></td>
                </tr>
            }
        </tbody>
    </table>

    <div class="card mb-3">
        <div class="card-body">
            <h6>Add Line Item</h6>
            <div class="row g-2">
                <div class="col-md-5">
                    <input class="form-control" placeholder="Description" @bind="newItem.Description" />
                </div>
                <div class="col-md-2">
                    <input type="number" class="form-control" placeholder="Qty" @bind="newItem.Quantity" />
                </div>
                <div class="col-md-3">
                    <input type="number" step="0.01" class="form-control" placeholder="Amount" @bind="newItem.Amount" />
                </div>
                <div class="col-md-2">
                    <button class="btn btn-primary w-100" @onclick="AddItem">Add</button>
                </div>
            </div>
        </div>
    </div>

    <h5 class="mt-4">Payments</h5>
    <table class="table table-sm">
        <thead>
            <tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th><th>Type</th></tr>
        </thead>
        <tbody>
            @foreach (var p in invoice.Payments)
            {
                <tr>
                    <td>@p.Date.ToString("yyyy-MM-dd HH:mm")</td>
                    <td>@p.Amount.ToString("C")</td>
                    <td>@p.Method</td>
                    <td>@p.Reference</td>
                    <td>@(p.IsRefund ? "Refund" : "Payment")</td>
                </tr>
            }
        </tbody>
    </table>

    @if (invoice.Status != VetClinic.Models.InvoiceStatus.Paid)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h6>Process Payment</h6>
                <div class="row g-2">
                    <div class="col-md-3">
                        <input type="number" step="0.01" class="form-control" placeholder="Amount" @bind="newPayment.Amount" />
                    </div>
                    <div class="col-md-3">
                        <select class="form-select" @bind="newPayment.Method">
                            @foreach (var method in Enum.GetValues<VetClinic.Models.PaymentMethod>())
                            {
                                <option value="@method">@method</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Reference" @bind="newPayment.Reference" />
                    </div>
                    <div class="col-md-3">
                        <button class="btn btn-success w-100" @onclick="ProcessPayment">Pay</button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private VetClinic.Models.Invoice? invoice;
    private VetClinic.Models.InvoiceItem newItem = new() { Quantity = 1 };
    private VetClinic.Models.Payment newPayment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await BillingService.GetInvoiceAsync(Id);
    }

    private async Task AddItem()
    {
        newItem.InvoiceId = Id;
        await BillingService.AddInvoiceItemAsync(newItem);
        newItem = new() { Quantity = 1 };
        await LoadInvoice();
    }

    private async Task RemoveItem(int itemId)
    {
        await BillingService.RemoveInvoiceItemAsync(itemId);
        await LoadInvoice();
    }

    private async Task ProcessPayment()
    {
        newPayment.InvoiceId = Id;
        newPayment.Date = DateTime.Now;
        await BillingService.ProcessPaymentAsync(newPayment);
        newPayment = new();
        await LoadInvoice();
    }

    private string GetStatusBadge(VetClinic.Models.InvoiceStatus status) => status switch
    {
        VetClinic.Models.InvoiceStatus.Pending => "bg-warning text-dark",
        VetClinic.Models.InvoiceStatus.Paid => "bg-success",
        VetClinic.Models.InvoiceStatus.Overdue => "bg-danger",
        VetClinic.Models.InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

